class MyHashMap:
    def __init__(self):
        self.size = 1000
        self.table = [[] for _ in range(self.size)]
    def put(self, key, value):
        bucket = self.table[key % self.size]
        for i, (k, v) in enumerate(bucket):
            if k == key: bucket[i][1] = value; return
        bucket.append([key, value])
    def get(self, key):
        bucket = self.table[key % self.size]
        for k, v in bucket:
            if k == key: return v
        return -1
    def remove(self, key):
        bucket = self.table[key % self.size]
        for i, (k, v) in enumerate(bucket):
            if k == key: bucket.pop(i); return

